export interface Issue {
  source: IssueSource
  severity: Severity
  title: string
  filePath: string
  line: number
  column?: number
  endLine?: number
  ruleId?: string | null
  code?: string
  category?: string
  confidence?: number
  fixable?: boolean
  description: string
  recommendation?: string
  suggestedFix?: string
  related?: { message: string; depth: number }[]
  snippet?: { startLine: number; code: string }
  /** Primary external reference label + url. */
  reference?: string
  /** CVE identifiers (security + deps). */
  cves?: string[]
  /** Dependency-specific metadata, present when source === "deps". */
  dep?: {
    name: string
    current: string
    latest?: string
    fixedIn?: string
    type: string
    kind: string
    license?: string
    usedIn?: string[]
  }
  /** Environment-variable metadata, present when source === "env". */
  env?: {
    key: string
    scope: string
    status: string
    usedIn: string[]
    definedIn: string[]
    sample?: string
  }
  /** Network-call metadata, present when source === "network". */
  net?: {
    url: string
    host: string
    method: string
    client: string
    secure: boolean
    external: boolean
    issues: { kind: string; severity: Severity; message: string }[]
  }
  /** Database-finding metadata, present when source === "database". */
  db?: {
    engine: string
    kind: string
    target?: string
  }
  /** Accessibility-violation metadata, present when source === "a11y". */
  a11y?: {
    rule: string
    impact: string
    principle: string
    wcag: string[]
    helpUrl: string
    selector: string
    nodes: number
  }
  /** Performance-finding metadata, present when source === "perf". */
  perf?: {
    kind: string
    estimatedSavingKb?: number
  }
  /** Test-finding metadata, present when source === "tests". */
  test?: {
    kind: string
  }
}

